mapper.select:
SELECT id, tenant_id, prompt_id, name, description,
       template_text, variables, version, status, ab_test_config,
       created_at, updated_at
FROM t_prompt_template
WHERE tenant_id = #{tenantId}
  AND status = #{status}
  AND deleted = 0
ORDER BY updated_at DESC
LIMIT #{size} OFFSET #{offset}

SELECT id, tenant_id, prompt_id, name, description,
       template_text, variables, version, status, ab_test_config,
       created_at, updated_at
FROM t_prompt_template
WHERE tenant_id = #{tenantId}
  AND name = #{name}
  AND version = #{version}
  AND deleted = 0
LIMIT 1
